namespace sv_84013c29aa4f45fdbd29ad59e5a37f0a.Services;

public sealed class WarehouseInfo
{
    public required string Id { get; init; }
    public required string Name { get; init; }
}

/// <summary>
/// Scoped service that holds the currently-selected warehouse for one circuit.
/// Every interactive component on the same circuit shares this instance,
/// so each browser tab / user gets independent state.
/// </summary>
public sealed class WarehouseState
{
    public static readonly IReadOnlyList<WarehouseInfo> AvailableWarehouses =
    [
        new() { Id = "WH-001", Name = "Warehouse A – East" },
        new() { Id = "WH-002", Name = "Warehouse B – West" },
        new() { Id = "WH-003", Name = "Warehouse C – Central" },
    ];

    private string _selectedWarehouseId = AvailableWarehouses[0].Id;

    public string SelectedWarehouseId => _selectedWarehouseId;

    public string SelectedWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _selectedWarehouseId).Name;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_selectedWarehouseId == warehouseId) return;
        _selectedWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_84013c29aa4f45fdbd29ad59e5a37f0a.Services;

/// <summary>
/// Scoped service that provides low-stock alert counts and notifies
/// all subscribers when fresh data arrives.  Because it is scoped,
/// each circuit (user) has its own instance and its own alert count.
/// </summary>
public sealed class InventoryAlertService
{
    private readonly Random _random = new();

    public int LatestLowStockCount { get; private set; }

    /// <summary>Fired after new alert data is fetched. All subscribers re-render.</summary>
    public event Action? OnAlertDataChanged;

    /// <summary>
    /// Simulates a database query that returns the number of items
    /// below minimum stock levels for a given warehouse.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate I/O latency and a random count 0–15.
        var count = _random.Next(0, 16);
        return Task.FromResult(count);
    }

    /// <summary>
    /// Fetches the latest count and notifies every subscriber.
    /// Called by whichever component owns the polling timer.
    /// </summary>
    public async Task RefreshAsync(string warehouseId)
    {
        LatestLowStockCount = await GetLowStockCountAsync(warehouseId);
        OnAlertDataChanged?.Invoke();
    }
}

@using sv_84013c29aa4f45fdbd29ad59e5a37f0a.Services
@inject WarehouseState Warehouse
@implements IDisposable

<div class="warehouse-selector">
    <label class="form-label text-white small mb-1">Current Warehouse</label>
    <select class="form-select form-select-sm"
            value="@Warehouse.SelectedWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseState.AvailableWarehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var newId = e.Value?.ToString();
        if (!string.IsNullOrEmpty(newId))
        {
            Warehouse.SetWarehouse(newId);
        }
    }

    protected override void OnInitialized()
    {
        Warehouse.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        Warehouse.OnChange -= StateHasChanged;
    }
}

@using sv_84013c29aa4f45fdbd29ad59e5a37f0a.Services
@inject InventoryAlertService Alerts
@implements IDisposable

@if (Alerts.LatestLowStockCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-auto">@Alerts.LatestLowStockCount</span>
}
else
{
    <span class="badge bg-success rounded-pill ms-auto">0</span>
}

@code {
    protected override void OnInitialized()
    {
        Alerts.OnAlertDataChanged += OnDataChanged;
    }

    private void OnDataChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        Alerts.OnAlertDataChanged -= OnDataChanged;
    }
}

