namespace sv_84013c29aa4f45fdbd29ad59e5a37f0a.Services;

public sealed class WarehouseInfo
{
    public required string Id { get; init; }
    public required string Name { get; init; }
}

/// <summary>
/// Scoped service that holds the currently-selected warehouse for one circuit.
/// Every interactive component on the same circuit shares this instance,
/// so each browser tab / user gets independent state.
/// </summary>
public sealed class WarehouseState
{
    public static readonly IReadOnlyList<WarehouseInfo> AvailableWarehouses =
    [
        new() { Id = "WH-001", Name = "Warehouse A – East" },
        new() { Id = "WH-002", Name = "Warehouse B – West" },
        new() { Id = "WH-003", Name = "Warehouse C – Central" },
    ];

    private string _selectedWarehouseId = AvailableWarehouses[0].Id;

    public string SelectedWarehouseId => _selectedWarehouseId;

    public string SelectedWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _selectedWarehouseId).Name;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_selectedWarehouseId == warehouseId) return;
        _selectedWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

