+@page "/dashboard"
+@using sv_84013c29aa4f45fdbd29ad59e5a37f0a.Services
+@rendermode InteractiveServer
+@inject WarehouseState Warehouse
+@inject InventoryAlertService Alerts
+@implements IAsyncDisposable
+
+<PageTitle>Dashboard – @Warehouse.SelectedWarehouseName</PageTitle>
+
+<h1>Warehouse Dashboard</h1>
+
+<div class="alert alert-info d-flex align-items-center" role="alert">
+    <strong class="me-2">Active site:</strong> @Warehouse.SelectedWarehouseName (@Warehouse.SelectedWarehouseId)
+</div>
+
+<div class="row g-4 mb-4">
+    <div class="col-md-4">
+        <div class="card text-bg-@(Alerts.LatestLowStockCount > 10 ? "danger" : Alerts.LatestLowStockCount > 5 ? "warning" : "success") shadow-sm">
+            <div class="card-body text-center">
+                <h5 class="card-title">Low-Stock Alerts</h5>
+                <p class="display-3 fw-bold mb-0">@Alerts.LatestLowStockCount</p>
+                <p class="card-text small mt-1">items below minimum level</p>
+            </div>
+        </div>
+    </div>
+
+    <div class="col-md-4">
+        <div class="card shadow-sm">
+            <div class="card-body text-center">
+                <h5 class="card-title">Polling Status</h5>
+                <p class="mb-0">
+                    @if (_isPolling)
+                    {
+                        <span class="badge bg-success">Active – every 10 s</span>
+                    }
+                    else
+                    {
+                        <span class="badge bg-secondary">Stopped</span>
+                    }
+                </p>
+                <p class="text-muted small mt-2 mb-0">Last refresh: @_lastRefresh.ToString("T")</p>
+            </div>
+        </div>
+    </div>
+
+    <div class="col-md-4">
+        <div class="card shadow-sm">
+            <div class="card-body text-center">
+                <h5 class="card-title">Selected Warehouse</h5>
+                <p class="display-6 mb-0">@Warehouse.SelectedWarehouseId</p>
+                <p class="text-muted small mt-1">@Warehouse.SelectedWarehouseName</p>
+            </div>
+        </div>
+    </div>
+</div>
+
+<div class="card shadow-sm">
+    <div class="card-header">
+        <h5 class="mb-0">Alert History (last @_history.Count polls)</h5>
+    </div>
+    <div class="card-body p-0">
+        <table class="table table-striped mb-0">
+            <thead>
+                <tr>
+                    <th>Time</th>
+                    <th>Warehouse</th>
+                    <th>Low-Stock Count</th>
+                </tr>
+            </thead>
+            <tbody>
+                @foreach (var entry in _history.AsEnumerable().Reverse())
+                {
+                    <tr>
+                        <td>@entry.Time.ToString("T")</td>
+                        <td>@entry.WarehouseId</td>
+                        <td>
+                            <span class="badge bg-@(entry.Count > 10 ? "danger" : entry.Count > 5 ? "warning" : "success")">
+                                @entry.Count
+                            </span>
+                        </td>
+                    </tr>
+                }
+            </tbody>
+        </table>
+    </div>
+</div>
+
+@code {
+    private PeriodicTimer? _timer;
+    private CancellationTokenSource? _cts;
+    private bool _isPolling;
+    private DateTime _lastRefresh = DateTime.Now;
+    private readonly List<AlertEntry> _history = new();
+
+    private sealed record AlertEntry(DateTime Time, string WarehouseId, int Count);
+
+    protected override async Task OnInitializedAsync()
+    {
+        Warehouse.OnChange += OnWarehouseChanged;
+        Alerts.OnAlertDataChanged += OnAlertDataChanged;
+
+        await Alerts.RefreshAsync(Warehouse.SelectedWarehouseId);
+        RecordHistory();
+
+        StartPolling();
+    }
+
+    private void StartPolling()
+    {
+        StopPolling();
+        _cts = new CancellationTokenSource();
+        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
+        _isPolling = true;
+        _ = PollLoopAsync(_cts.Token);
+    }
+
+    private void StopPolling()
+    {
+        _isPolling = false;
+        _cts?.Cancel();
+        _cts?.Dispose();
+        _cts = null;
+        _timer?.Dispose();
+        _timer = null;
+    }
+
+    private async Task PollLoopAsync(CancellationToken ct)
+    {
+        try
+        {
+            while (await _timer!.WaitForNextTickAsync(ct))
+            {
+                await Alerts.RefreshAsync(Warehouse.SelectedWarehouseId);
+                RecordHistory();
+                _lastRefresh = DateTime.Now;
+                await InvokeAsync(StateHasChanged);
+            }
+        }
+        catch (OperationCanceledException) { }
+    }
+
+    private void RecordHistory()
+    {
+        _history.Add(new AlertEntry(DateTime.Now, Warehouse.SelectedWarehouseId, Alerts.LatestLowStockCount));
+        if (_history.Count > 20) _history.RemoveAt(0);
+    }
+
+    private async void OnWarehouseChanged()
+    {
+        // Warehouse switched — refresh immediately and restart polling.
+        await Alerts.RefreshAsync(Warehouse.SelectedWarehouseId);
+        RecordHistory();
+        _lastRefresh = DateTime.Now;
+        StartPolling();
+        await InvokeAsync(StateHasChanged);
+    }
+
